// Process Telegram updates and filter for new ones
const response = $input.first().json;
const updates = response.result || [];

if (updates.length === 0) {
  return [];
}

// Get the last processed update ID from static data
const staticData = $input.item?.staticData || {};
const lastUpdateId = staticData.lastUpdateId || 0;

// Filter for new updates only
const newUpdates = updates.filter(u => u.update_id > lastUpdateId);

if (newUpdates.length === 0) {
  return [];
}

// Update the last processed ID
const maxUpdateId = Math.max(...newUpdates.map(u => u.update_id));

// Process each new update
const processed = newUpdates.map(update => {
  let from = '';
  let chatId = '';
  let text = '';
  let updateId = update.update_id.toString();

  if (update.callback_query) {
    from = update.callback_query.from.id.toString();
    chatId = update.callback_query.message.chat.id.toString();
    text = update.callback_query.data || '';
  } else if (update.message) {
    from = update.message.from.id.toString();
    chatId = update.message.chat.id.toString();
    text = update.message.text || '';
  }

  // Only process messages from the cleaner (chat_id PLACEHOLDER_CHAT_ID)
  if (chatId !== 'PLACEHOLDER_CHAT_ID') {
    return null;
  }

  // Classify the message
  const lowerText = text.toLowerCase().trim();
  let messageType = 'unknown';
  let priority = 'normal';

  const doneKeywords = ['done', 'finished', 'complete', 'completed', 'all done', 'cleaned', 'all good', 'all set', '✅', 'done!'];
  const issueKeywords = ['broken', 'damage', 'damaged', 'fix', 'repair', 'issue', 'problem', 'stain', 'missing', 'leak', 'mold', 'crack', 'hole', '🚨'];
  const questionKeywords = ['?', 'where', 'when', 'what', 'how', 'which', 'can i', 'should i', 'do i', 'help'];

  if (doneKeywords.some(kw => lowerText.includes(kw))) {
    messageType = 'job_complete';
  } else if (issueKeywords.some(kw => lowerText.includes(kw))) {
    messageType = 'maintenance_issue';
    priority = 'high';
  } else if (questionKeywords.some(kw => lowerText.includes(kw))) {
    messageType = 'question';
  } else {
    messageType = 'general';
  }

  return {
    json: {
      from: from,
      chat_id: chatId,
      text: text,
      messageType: messageType,
      priority: priority,
      updateId: updateId,
      maxUpdateId: maxUpdateId,
      receivedAt: new Date().toISOString()
    }
  };
}).filter(u => u !== null);

if (processed.length === 0) {
  return [];
}

return processed;

// Store the last update ID for next run
const maxUpdateId = $input.first().json.maxUpdateId;

// This node just passes through but sets up static data for next run
return $input.all();

